#include <iostream>
#include <vector>
#include <cmath>
#include <cstring>
#include <cstdint>

#include "decode_kernel.h" // keep your kernel header

int main() {
    const int num_layers   = 4;
    const int num_classes  = 3;
    const int output_dim   = num_classes + 64;
    const int max_boxes_num = 8192;   // global capacity
    const int tmp_capacity   = 2048;  // per-layer temporary capacity (requested)

    // Global (accumulated) outputs across all layers
    static float out_boxes_x[max_boxes_num];
    static float out_boxes_y[max_boxes_num];
    static float out_boxes_w[max_boxes_num];
    static float out_boxes_h[max_boxes_num];
    static int   out_cls[max_boxes_num];
    static float out_score[max_boxes_num];
    int global_box_count = 0; // number of boxes stored so far

    int layer_sizes[num_layers] = {200, 100, 50, 25};
    float layer_strides[num_layers] = {4.0f, 8.0f, 16.0f, 32.0f};
    float det_scales = 0.1f; // same for all layers in this test

    for (int layer = 0; layer < num_layers; ++layer) {
        int layer_size = layer_sizes[layer];
        int total_size = layer_size * layer_size * output_dim;

        const int WORD_BYTES = 8;
        const int PACKED_SIZE = (total_size + WORD_BYTES - 1) / WORD_BYTES;
        ap_uint<64> input_data[PACKED_SIZE];
        // Fill packed input data
        for (int i = 0; i < PACKED_SIZE; ++i) {
            ap_uint<64> word = 0;
            for (int b = 0; b < WORD_BYTES; ++b) {
                int idx = i * WORD_BYTES + b;
                if (idx < total_size) {
                    int8_t val = (int8_t)((idx % 127) - 63);
                    word.range(b * 8 + 7, b * 8) = (ap_uint<8>)val;
                }
            }
            input_data[i] = word;
        }

        // Temporary outputs for this single layer with fixed capacity = 2048
        float tmp_boxes_x[tmp_capacity];
        float tmp_boxes_y[tmp_capacity];
        float tmp_boxes_w[tmp_capacity];
        float tmp_boxes_h[tmp_capacity];
        int   tmp_cls[tmp_capacity];
        float tmp_score[tmp_capacity];
        int tmp_box_num = 0; // kernel will set this to number of boxes it wrote

        // Call kernel for this layer: write into temporary buffers
        decode_kernel(
            input_data,                  // int8_t* input
            layer_size,                  // int grid size
            layer_strides[layer],        // float stride
            tmp_boxes_x,                 // float* out_boxes_x
            tmp_boxes_y,                 // float* out_boxes_y
            tmp_boxes_w,                 // float* out_boxes_w
            tmp_boxes_h,                 // float* out_boxes_h
            tmp_cls,                     // int* out_cls
            tmp_score,                   // float* out_score
            tmp_box_num                  // int out_box_num
        );

        if (tmp_box_num < 0) tmp_box_num = 0; // defensive

        // Copy tmp results into global arrays at offset = global_box_count
        for (int i = 0; i < tmp_box_num; ++i) {
            int dst = global_box_count + i;
            out_boxes_x[dst] = tmp_boxes_x[i];
            out_boxes_y[dst] = tmp_boxes_y[i];
            out_boxes_w[dst] = tmp_boxes_w[i];
            out_boxes_h[dst] = tmp_boxes_h[i];
            out_cls[dst]     = tmp_cls[i];
            out_score[dst]   = tmp_score[i];
        }

        // Advance global counter
        global_box_count += tmp_box_num;
    }

    // Final summary
    std::cout << "Total boxes decoded: " << global_box_count << '\n';
    for (int i = 0; i < global_box_count && i < 5; ++i) {
        std::cout << "Box " << i
                  << ": cx=" << out_boxes_x[i]
                  << " cy=" << out_boxes_y[i]
                  << " w="  << out_boxes_w[i]
                  << " h="  << out_boxes_h[i]
                  << " class=" << out_cls[i]
                  << " score=" << out_score[i] << '\n';
    }

    return 0;
}
